What does this component show when `role` is "admin"?

```jsx
function NavBar({ role }) {
  return (
    <nav>
      <a href="/home">Home</a>
      <a href="/profile">Profile</a>
      {role === "admin" && <a href="/admin">Admin Panel</a>}
    </nav>
  );
}
```

What does this render when `status` is "loading"?

```jsx
function StatusDisplay({ status, data }) {
  return (
    <div>
      {status === "loading" ? (
        <p>Loading...</p>
      ) : status === "error" ? (
        <p>Something went wrong</p>
      ) : (
        <p>Result: {data}</p>
      )}
    </div>
  );
}
```

This component has the `&&` zero gotcha. What does the user see when `messageCount` is 0?

```jsx
function Inbox({ messageCount }) {
  return (
    <div className="inbox">
      <h2>Inbox</h2>
      {messageCount && (
        <span className="count">{messageCount} new messages</span>
      )}
    </div>
  );
}
```
